// Normalize incoming lead records to a stable schema
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  out.push({ json: {
    leadId: String(j.leadId ?? j.id ?? '').trim(),
    email: typeof j.email === 'string' ? j.email.trim() : j.email ?? null,
    source: j.source ?? 'api',
    receivedAt: new Date().toISOString(),
  } });
}
return out;

